#include <stdio.h>
#include <stdlib.h>
typedef long long ll;
typedef struct {int n; ll *bit;} BIT;
BIT* newBIT(int n){BIT* t=malloc(sizeof(BIT));t->n=n;t->bit=calloc(n+2,sizeof(ll));return t;}
void bitAdd(BIT* t,int idx,ll val){for(int i=idx;i<=t->n;i+=i&-i) t->bit[i]+=val;}
void rangeAdd(BIT* t,int l,int r,ll val){bitAdd(t,l,val); if(r+1<=t->n) bitAdd(t,r+1,-val);}
ll pointQuery(BIT* t,int idx){ll res=0; for(int i=idx;i>0;i-=i&-i) res+=t->bit[i]; return res;}
int main(){int T; if(scanf("%d",&T)!=1) return 0; while(T--){int N,Q; scanf("%d %d",&N,&Q); ll *A=malloc((N+1)*sizeof(ll)); for(int i=1;i<=N;i++) scanf("%lld",&A[i]); BIT *fa=newBIT(N), *fb=newBIT(N), *fc=newBIT(N);
 for(int qi=0; qi<Q; ++qi){int type; scanf("%d",&type); if(type==1){int L,R; ll X; scanf("%d %d %lld",&L,&R,&X); ll d = X - L; ll a = 1; ll b = 2*d; ll c = d*d; rangeAdd(fa,L,R,a); rangeAdd(fb,L,R,b); rangeAdd(fc,L,R,c); }
 else{int Y; scanf("%d",&Y); ll a = pointQuery(fa,Y); ll b = pointQuery(fb,Y); ll c = pointQuery(fc,Y); ll ans = A[Y] + a*Y*Y + b*Y + c; printf("%lld\n",ans); } }
 free(A); free(fa->bit); free(fa); free(fb->bit); free(fb); free(fc->bit); free(fc);
 }
