import java.io.*;
import java.util.*;

public class Main {
    static class BIT {
        int n; long[] bit;
        BIT(int n){this.n=n; bit=new long[n+2];}
        void add(int idx,long val){for(int i=idx;i<=n;i+=i&-i) bit[i]+=val;}
        void rangeAdd(int l,int r,long val){add(l,val); if(r+1<=n) add(r+1,-val);}
        long point(int idx){long res=0; for(int i=idx;i>0;i-=i&-i) res+=bit[i]; return res;}
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int Q = fs.nextInt();
            long[] A = new long[N+1];
            for (int i=1;i<=N;i++) A[i]=fs.nextLong();
            BIT fa = new BIT(N), fb = new BIT(N), fc = new BIT(N);
            for (int i=0;i<Q;i++) {
                int type = fs.nextInt();
                if (type==1) {
                    int L = fs.nextInt();
                    int R = fs.nextInt();
                    long X = fs.nextLong();
                    long d = X - L;
                    long a = 1;
                    long b = 2*d;
                    long c = d*d;
                    fa.rangeAdd(L,R,a);
                    fb.rangeAdd(L,R,b);
                    fc.rangeAdd(L,R,c);
                } else {
                    int Y = fs.nextInt();
                    long a = fa.point(Y);
                    long b = fb.point(Y);
                    long c = fc.point(Y);
                    long ans = A[Y] + a*Y*Y + b*Y + c;
                    out.append(ans).append('\n');
                }
            }
        }
        System.out.print(out.toString());
    }
    // Fast scanner
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in){this.in=in;}
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        long nextLong() throws IOException { int c; do {c = readByte();} while (c <= ' ');
            boolean neg = false; if (c=='-'){neg=true; c=readByte();}
            long val=0; while (c>' ') {val = val*10 + (c-'0'); c=readByte();}
            return neg?-val:val; }
        int nextInt() throws IOException { return (int)nextLong(); }
    }
}

