const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
if (data.length===0) process.exit(0);
const T = Number(data[idx++]);
let output = [];
for (let t=0; t<T; ++t){
  const N = Number(data[idx++]);
  const Q = Number(data[idx++]);
  const A = new Array(N+1);
  A[0]=0;
  for(let i=1;i<=N;i++) A[i]=BigInt(data[idx++]);
  const fa = new Array(N+2).fill(0n);
  const fb = new Array(N+2).fill(0n);
  const fc = new Array(N+2).fill(0n);
  const bitAdd = (bit, i, val)=>{while(i<=N){bit[i]+=val;i+=i&-i;}};
  const rangeAdd = (bit,l,r,val)=>{bitAdd(bit,l,val); if(r+1<=N) bitAdd(bit,r+1,-val);};
  const pointQuery = (bit,i)=>{let s=0n; while(i>0){s+=bit[i]; i-=i&-i;} return s;};
  for(let q=0;q<Q;q++){
    const type = Number(data[idx++]);
    if(type===1){
      const L = Number(data[idx++]);
      const R = Number(data[idx++]);
      const X = BigInt(data[idx++]);
      const d = X - BigInt(L);
      const a = 1n;
      const b = 2n * d;
      const c = d * d;
      rangeAdd(fa, L, R, a);
      rangeAdd(fb, L, R, b);
      rangeAdd(fc, L, R, c);
    } else {
      const Y = Number(data[idx++]);
      const a = pointQuery(fa, Y);
      const b = pointQuery(fb, Y);
      const c = pointQuery(fc, Y);
      const ans = A[Y] + a*BigInt(Y)*BigInt(Y) + b*BigInt(Y) + c;
      output.push(ans.toString());
    }
  }
}
